components.calculateValue:
var year = '';
if (data.startDate) {
  var d = new Date(data.startDate);
  if (!isNaN(d.getTime())) year = d.getFullYear();
}
var type = data.contractType || 'UW';
var orgName = '';
if (data.organization && data.organization.data && data.organization.data.name) {
  orgName = data.organization.data.name;
} else if (data.organization && typeof data.organization === 'string') {
  orgName = '';
}
var abbr = orgName.replace(/[^a-zA-Z0-9]/g, '').substring(0, 8).toUpperCase() || 'ORG';
var seq = 'NEW';
if (instance && instance.root && instance.root.submission && instance.root.submission._id) {
  var id = instance.root.submission._id;
  seq = String(parseInt(id.slice(-4), 16) % 1000).padStart(3, '0');
}
if (year && abbr !== 'ORG') {
  value = year + '-' + type + '-' + abbr + '-' + seq;
} else {
  value = '';
}
